    // 4. 负载
    if (payload_len > 0) {
        memcpy(&packet[CMP_HEADER_SIZE], payload, payload_len);
    }
    // 5. 校验和 (简单逻辑：计算负载区域的低8位和)
    uint8_t checksum = 0;
    for (size_t i = 0; i < payload_len; i++) {
